import React, { useContext, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Container } from 'react-bootstrap'; 

// Importaciones de Contextos
import { SettingsContext } from '../context/SettingsContext'; 
// ELIMINADOS: AuthContext, CartContext, SearchBox, Dropdown.

const Header = () => {
  // Solo necesitamos settings para el nombre del sitio
  const { settings } = useContext(SettingsContext); 

  useEffect(() => {
    // Aplicar el color de acento de la configuración a las variables CSS globales
    if (settings?.accentColor) {
      document.documentElement.style.setProperty('--cta-color', settings.accentColor);
    }
  }, [settings]);

  // ELIMINAMOS baseLinkClasses para aplicar estilos directamente y evitar conflictos.
  
  return (
    // CRÍTICO: Fondo negro profundo (--brand-dark) y redondeo inferior
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md rounded-b-xl"
      // CRÍTICO: FORZAMOS EL COLOR DE FONDO NEGRO PROFUNDO CON ESTILO INLINE.
      // También forzamos un padding vertical para que el contenido no esté tan apretado.
      style={{ 
        backgroundColor: 'var(--brand-dark)',
        paddingTop: '1rem', // Añade espacio superior
        paddingBottom: '1rem' // Añade espacio inferior
      }} 
    >
      <Container> 
        <div className="d-flex justify-content-start align-items-center"> 
          
          {/* 1. Logo de Texto/Eslogan - ESTILOS CRÍTICOS DIRECTOS */}
          <Link 
            to="/" 
            // ELIMINAMOS baseLinkClasses aquí para evitar el color azul y subrayado
            className="flex flex-col items-start h-full no-underline" // flex-col para apilar verticalmente
          > 
            {/* Nombre: Blanco, grande, negrita, mayúsculas */}
            <span 
              className="text-white text-3xl font-extrabold tracking-wider uppercase" 
              style={{ lineHeight: 1 }} // Asegura que las líneas no tengan exceso de espacio
            >
              {settings?.siteName || 'Tecnotitlán'}
            </span>
            {/* Eslogan: Gris opaco, pequeño */}
            <span 
              className="text-gray-400 text-xs font-light tracking-wide mt-1" // mt-1 para un pequeño margen superior
              style={{ lineHeight: 1 }} 
            >
              Tecnología con Raíces
            </span>
          </Link>
          
          {/* Aquí termina el contenido del Header. */}
          
        </div>
      </Container>
    </header>
  );
};

export default Header;
